702	// Recursive case-insensitive lookup function used by n.findCaseInsensitivePath
703	func (n *node) findCaseInsensitivePathRec(path string, ciPath []byte, rb [4]byte, fixTrailingSlash bool) []byte {
704		npLen := len(n.path)
705	
706	walk: // Outer loop for walking the tree
707		for len(path) >= npLen && (npLen == 0 || strings.EqualFold(path[1:npLen], n.path[1:])) {
708			// Add common prefix to result
709			oldPath := path
710			path = path[npLen:]
711			ciPath = append(ciPath, n.path...)
712	
713			if len(path) == 0 {
714				// We should have reached the node containing the handle.
715				// Check if this node has a handle registered.
716				if n.handlers != nil {
717					return ciPath
718				}
719	
720				// No handle found.
721				// Try to fix the path by adding a trailing slash
722				if fixTrailingSlash {
723					for i, c := range []byte(n.indices) {
724						if c == '/' {
725							n = n.children[i]
726							if (len(n.path) == 1 && n.handlers != nil) ||
727								(n.nType == catchAll && n.children[0].handlers != nil) {
728								return append(ciPath, '/')
729							}
730							return nil
731						}
732					}
733				}
734				return nil
735			}
736	
737			// If this node does not have a wildcard (param or catchAll) child,
738			// we can just look up the next child node and continue to walk down
739			// the tree
740			if !n.wildChild {
741				// Skip rune bytes already processed
742				rb = shiftNRuneBytes(rb, npLen)
743	
744				if rb[0] != 0 {
745					// Old rune not finished
746					idxc := rb[0]
747					for i, c := range []byte(n.indices) {
748						if c == idxc {
749							// continue with child node
750							n = n.children[i]
751							npLen = len(n.path)
752							continue walk
753						}
754					}
755				} else {
756					// Process a new rune
757					var rv rune
758	
759					// Find rune start.
760					// Runes are up to 4 byte long,
761					// -4 would definitely be another rune.
762					var off int
763					for max_ := min(npLen, 3); off < max_; off++ {
764						if i := npLen - off; utf8.RuneStart(oldPath[i]) {
765							// read rune from cached path
766							rv, _ = utf8.DecodeRuneInString(oldPath[i:])
767							break
768						}
769					}
770	
771					// Calculate lowercase bytes of current rune
772					lo := unicode.ToLower(rv)
773					utf8.EncodeRune(rb[:], lo)
774	
775					// Skip already processed bytes
776					rb = shiftNRuneBytes(rb, off)
777	
778					idxc := rb[0]
779					for i, c := range []byte(n.indices) {
780						// Lowercase matches
781						if c == idxc {
782							// must use a recursive approach since both the
783							// uppercase byte and the lowercase byte might exist
784							// as an index
785							if out := n.children[i].findCaseInsensitivePathRec(
786								path, ciPath, rb, fixTrailingSlash,
787							); out != nil {
788								return out
789							}
790							break
791						}
792					}
793	
794					// If we found no match, the same for the uppercase rune,
795					// if it differs
796					if up := unicode.ToUpper(rv); up != lo {
797						utf8.EncodeRune(rb[:], up)
798						rb = shiftNRuneBytes(rb, off)
799	
800						idxc := rb[0]
801						for i, c := range []byte(n.indices) {
802							// Uppercase matches
803							if c == idxc {
804								// Continue with child node
805								n = n.children[i]
806								npLen = len(n.path)
807								continue walk
808							}
809						}
810					}
811				}
812	
813				// Nothing found. We can recommend to redirect to the same URL
814				// without a trailing slash if a leaf exists for that path
815				if fixTrailingSlash && path == "/" && n.handlers != nil {
816					return ciPath
817				}
818				return nil
819			}
820	
821			// When wildChild is true, try static children first (via indices)
822			// before falling back to the wildcard child. This ensures that
823			// case-insensitive lookups prefer static routes over param routes
824			// (e.g., /PREFIX/XXX should resolve to /prefix/xxx, not match :id).
825			if len(n.indices) > 0 {
826				rb = shiftNRuneBytes(rb, npLen)
827	
828				if rb[0] != 0 {
829					idxc := rb[0]
830					for i, c := range []byte(n.indices) {
831						if c == idxc {
832							if out := n.children[i].findCaseInsensitivePathRec(
833								path, ciPath, rb, fixTrailingSlash,
834							); out != nil {
835								return out
836							}
837							break
838						}
839					}
840				} else {
841					var rv rune
842					var off int
843					for max_ := min(npLen, 3); off < max_; off++ {
844						if i := npLen - off; utf8.RuneStart(oldPath[i]) {
845							rv, _ = utf8.DecodeRuneInString(oldPath[i:])
846							break
847						}
848					}
849	
850					lo := unicode.ToLower(rv)
851					utf8.EncodeRune(rb[:], lo)
852					rb = shiftNRuneBytes(rb, off)
853	
854					idxc := rb[0]
855					for i, c := range []byte(n.indices) {
856						if c == idxc {
857							if out := n.children[i].findCaseInsensitivePathRec(
858								path, ciPath, rb, fixTrailingSlash,
859							); out != nil {
860								return out
861							}
862							break
863						}
864					}
865	
866					if up := unicode.ToUpper(rv); up != lo {
867						utf8.EncodeRune(rb[:], up)
868						rb = shiftNRuneBytes(rb, off)
869	
870						idxc := rb[0]
871						for i, c := range []byte(n.indices) {
872							if c == idxc {
873								if out := n.children[i].findCaseInsensitivePathRec(
874									path, ciPath, rb, fixTrailingSlash,
875								); out != nil {
876									return out
877								}
878								break
879							}
880						}
881					}
882				}
883			}
884	
885			// Fall back to wildcard child, which is always at the end of the array
886			n = n.children[len(n.children)-1]
887			switch n.nType {
888			case param:
889				// Find param end (either '/' or path end)
890				end := 0
891				for end < len(path) && path[end] != '/' {
892					end++
893				}
894	
895				// Add param value to case insensitive path
896				ciPath = append(ciPath, path[:end]...)
897	
898				// We need to go deeper!
899				if end < len(path) {
900					if len(n.children) > 0 {
901						// Continue with child node
902						n = n.children[0]
903						npLen = len(n.path)
904						path = path[end:]
905						continue
906					}
907	
908					// ... but we can't
909					if fixTrailingSlash && len(path) == end+1 {
910						return ciPath
911					}
912					return nil
913				}
914	
915				if n.handlers != nil {
916					return ciPath
917				}
918	
919				if fixTrailingSlash && len(n.children) == 1 {
920					// No handle found. Check if a handle for this path + a
921					// trailing slash exists
922					n = n.children[0]
923					if n.path == "/" && n.handlers != nil {
924						return append(ciPath, '/')
925					}
926				}
927	
928				return nil
929	
930			case catchAll:
931				return append(ciPath, path...)
932	
933			default:
934				panic("invalid node type")
935			}
936		}
937	
938		// Nothing found.
939		// Try to fix the path by adding / removing a trailing slash
940		if fixTrailingSlash {
941			if path == "/" {
942				return ciPath
943			}
944			if len(path)+1 == npLen && n.path[len(path)] == '/' &&
945				strings.EqualFold(path[1:], n.path[1:len(path)]) && n.handlers != nil {
946				return append(ciPath, n.path...)
947			}
948		}
949		return nil
950	}
